@startuml
package "com" {
    package "iluwatar" {
        package "dependency" {
            package "injection" {
                class "SimpleWizard" as SimpleWizard {
                    - tobacco : OldTobyTobacco
                    + SimpleWizard()
                    + smoke()
                }
                class "App" as App {
                    + App()
                    + main(args : String[])
                }
                class "AdvancedWizard" as AdvancedWizard {
                    - tobacco : Tobacco
                    + AdvancedWizard(tobacco : Tobacco)
                    + smoke()
                }
                class "GuiceWizard" as GuiceWizard {
                    - tobacco : Tobacco
                    + GuiceWizard(tobacco : Tobacco)
                    + smoke()
                }
                class "RivendellTobacco" as RivendellTobacco {
                    + RivendellTobacco()
                }
                class "OldTobyTobacco" as OldTobyTobacco {
                    + OldTobyTobacco()
                }
                class "SecondBreakfastTobacco" as SecondBreakfastTobacco {
                    + SecondBreakfastTobacco()
                }
                interface "Wizard" as Wizard {
                    + smoke()
                }
                abstract class "Tobacco" as Tobacco {
                    + Tobacco()
                    + smoke(wizard : Wizard)
                }
                SimpleWizard --> OldTobyTobacco : -tobacco
                AdvancedWizard ..> Wizard
                GuiceWizard ..> Wizard
                AdvancedWizard --> Tobacco : -tobacco
                GuiceWizard --> Tobacco : -tobacco
                RivendellTobacco --|> Tobacco
                OldTobyTobacco --|> Tobacco
                SecondBreakfastTobacco --|> Tobacco
                SimpleWizard ..> Wizard
            }
        }
    }
}
@enduml
